// Script Continued Below
var TaskTreeACLs = Class.create();
TaskTreeACLs.prototype = {
	initialize: function(grTaskTree) {
		this.grTree = grTaskTree;
		this.treeId = grTaskTree.getUniqueValue();
		this.active = false;
		this.isTaskManagerOUTA = false;
		var primary_assignee = '';
		// DFCT0011930 - get primary office
		// check if task manager of the top task Primary Assignee
		var UserPermissions = new UserInfoScripts();			
		var primary_office = '';

		if(grTaskTree.u_task_ref){
			var grTopTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
			if(grTopTask.get(grTaskTree.u_task_ref)){
				this.active = grTopTask.active;
				primary_assignee = grTopTask.getValue("primary_assignee") + '';
				// DFCT0011930 - get primary office
				primary_office = grTopTask.getValue("primary_office") + '';

			}
		}

		// for now check to make sure the user has a role
		this.userHasTaskRole = this.userHasRole();
		// these can be used later IF specific roles needed
		// put in later IF needed and check performance as 4 count queries will be run instead of 1
		//this.isTaskOwner = this.userHasSpecificRole("Owner");
		//this.isAssignedMember = this.userHasSpecificRole("Assigned Member");
		//this.isReviewer = this.userHasSpecificRole("Reviewer");
		//this.isOnBehalfOf = this.userHasSpecificRole("OnBehalfOf");

		this.isTaskManagerOUTA = UserPermissions.IsUserOUTA(gs.getUserID(),primary_assignee);		
		this.isTaskerApplicationAdmin = gs.getUser().hasRole("x_153465_discovert.tasker_application_admin");
		// DFCT0011930 - user primary office to determine Task Administrator permissions
		this.isTaskAdministratorGTA = UserPermissions.userIsTaskAdministratorForOU(primary_office);
		// DFCT0011930 - user primary office to determine Task Executive permissions
		this.isTaskExecutive = UserPermissions.userIsTaskExecutiveForOU(primary_office);

	},

	userHasRole: function(){
		var answer = false;
		var currentUser= gs.getUserID();
		var query = "u_task_tree=" + this.treeId;
		var count = 0;
		query = query + "^u_task_requester=" + currentUser + "^ORoriginator=" + currentUser +
			"^ORassigned_to=" + currentUser + "^ORu_reviewer=" + currentUser +
			"^ORon_behalf_of=" + currentUser;
		var gaRoleCheck = new GlideAggregate('x_153465_discovert_route_task_instance');
		// ServiceNow Certifier Update - not changing, no way for user to inject into this query - update later with more time
		gaRoleCheck.addEncodedQuery(query);
		gaRoleCheck.addAggregate("COUNT");
		gaRoleCheck.query();
		if(gaRoleCheck.next()){
			count = gaRoleCheck.getAggregate("COUNT");
		}
		answer = (count>0);
		return answer;
	},	
	// this function will be used IF individual roles matter, but for now it is not used
	userHasSpecificRole: function(role){
		var answer = false;
		var currentUser= gs.getUserID();
		var query = "u_task_tree=" + this.treeId;
		var count = 0;
		switch (role){
			case "Owner":
				query = query + "^u_task_requester=" + currentUser + "^ORoriginator=" + currentUser;
				break;
			case "Assigned Member":
				query = query + "^assigned_to=" + currentUser;
				break;
			case "Reviewer":
				query = query + "^u_reviewer=" + currentUser;
				break;
			case "OnBehalfOf":
				query = query + "^on_behalf_of=" + currentUser;
				break;				
		}
		var gaRoleCheck = new GlideAggregate('x_153465_discovert_route_task_instance');
		// ServiceNow Certifier Update - not changing, no way for user to inject into this query - update later with more time
		gaRoleCheck.addEncodedQuery(query);
		gaRoleCheck.addAggregate("COUNT");
		gaRoleCheck.query();
		if(gaRoleCheck.next()){
			count = gaRoleCheck.getAggregate("COUNT");
		}
		answer = (count>0);
		return answer;
	},

	canWrite: function (){
		var answer = false;
		// is the top task active
		if(this.active){
			answer = (this.userHasTaskRole || this.isTaskManagerOUTA || this.isTaskerApplicationAdmin ||
						this.isTaskAdministratorGTA || this.isTaskExecutive);
		}
		return answer;
	},


	type: 'TaskTreeACLs'
};
